        do {
            guard let data = try KeychainStore.shared.get(service: service, account: account) else {
                session = nil
                isAuthenticated = false
                return
            }
            let decoder = JSONDecoder()
            decoder.dateDecodingStrategy = .iso8601
            session = try decoder.decode(AuthSession.self, from: data)
            isAuthenticated = (session != nil)
        } catch {
            session = nil
            isAuthenticated = false
        }
    }
    
    func setSession(_ s: AuthSession?) {
        session = s
        isAuthenticated = (s != nil)
        do {
            if let s = s {
                let encoder = JSONEncoder()
                encoder.dateEncodingStrategy = .iso8601
                try KeychainStore.shared.set(try encoder.encode(s), service: service, account: account)
            } else {
                try KeychainStore.shared.delete(service: service, account: account)
            }
        } catch { }
    }
    
    var accessToken: String? { session?.accessToken }
    var accountId: String? { session?.accountId }
}

