// MARK: - Real-time Quotes (WebSocket)

final class QuotesStream: ObservableObject {
    @Published private(set) var quotes: [String: Quote] = [:]
    @Published private(set) var isConnected: Bool = false
    
    private var task: URLSessionWebSocketTask?
    private var pingTimer: Timer?
    private let lock = NSLock()
    
    struct StreamMessage: Codable {
        let type: String
        let quote: Quote?
        let symbols: [String]?
        let error: String?
    }
    
    private let decoder: JSONDecoder = {
        let d = JSONDecoder()
        d.dateDecodingStrategy = .iso8601
        return d
    }()
    private let encoder: JSONEncoder = {
        let e = JSONEncoder()
        e.dateEncodingStrategy = .iso8601
        return e
    }()
    
    func connect(url: URL, authToken: String, symbols: [String]) {
        disconnect()
        
        var req = URLRequest(url: url)
        req.setValue("Bearer \(authToken)", forHTTPHeaderField: "Authorization")
        
        let session = URLSession(configuration: .default)
        let ws = session.webSocketTask(with: req)
        self.task = ws
        ws.resume()
        
        isConnected = true
        
        sendSubscribe(symbols: symbols)
        listen()
        
        pingTimer = Timer.scheduledTimer(withTimeInterval: 15, repeats: true) { [weak self] _ in
            self?.task?.sendPing { _ in }
        }
    }
    
    func disconnect() {
        pingTimer?.invalidate()
        pingTimer = nil
        if let t = task {
            t.cancel(with: .goingAway, reason: nil)
        }
        task = nil
        isConnected = false
    }
    
    func sendSubscribe(symbols: [String]) {
        guard let task else { return }
        let msg = ["type": "subscribe", "symbols": symbols.map { $0.uppercased() }] as [String: Any]
        guard let data = try? JSONSerialization.data(withJSONObject: msg) else { return }
        task.send(.data(data)) { _ in }
    }
    
    private func listen() {
        guard let task else { return }
        task.receive { [weak self] result in
            guard let self else { return }
            switch result {
            case .failure:
                DispatchQueue.main.async {
                    self.isConnected = false
                }
            case .success(let msg):
                let data: Data?
                switch msg {
                case .data(let d): data = d
                case .string(let s): data = s.data(using: .utf8)
                @unknown default: data = nil
                }
                if let data, let parsed = try? self.decoder.decode(StreamMessage.self, from: data) {
                    if parsed.type == "quote", let q = parsed.quote {
                        self.lock.lock()
                        self.quotes[q.symbol.uppercased()] = q
                        self.lock.unlock()
                        DispatchQueue.main.async {
                            self.objectWillChange.send()
                        }
                    }
                }
                self.listen()
            }
        }
    }
}

// MARK: - App State / ViewModels

@MainActor
final class TradingAppState: ObservableObject {
    @Published var portfolio: Portfolio?
    @Published var orders: [Order] = []
    @Published var selectedSymbol: String = "AAPL"
    @Published var quote: Quote?
    @Published var symbolResults: [String] = []
    @Published var toast: ToastMessage?
    @Published var isBusy: Bool = false
    @Published var lastError: AppError?
    
    @Published var orderSide: TradeSide = .buy
    @Published var orderType: OrderType = .market
    @Published var quantityText: String = "1"
    @Published var limitPriceText: String = ""
    @Published var tif: String = "DAY"
    
    let quotesStream = QuotesStream()
    private let service: TradingServiceProtocol
    private let auth: AuthStore
    private let debouncer = Debouncer()
    
    init(service: TradingServiceProtocol = TradingService(), auth: AuthStore = .shared) {
        self.service = service
        self.auth = auth
    }
    
    func showToast(_ text: String, kind: ToastKind = .info) {
        toast = ToastMessage(text: text, kind: kind)
        Task { @MainActor in
            try? await Task.sleep(nanoseconds: 2_000_000_000)
            if self.toast?.text == text { self.toast = nil }
        }
    }
    
    func refreshAll() async {
        guard let token = auth.accessToken else { return }
        isBusy = true
        defer { isBusy = false }
        do {
            async let p = service.getPortfolio(token: token)
            async let o = service.listOrders(token: token)
            let (portfolio, orders) = try await (p, o)
            self.portfolio = portfolio
            self.orders = orders.sorted { $0.createdAt > $1.createdAt }
            await refreshQuote(symbol: selectedSymbol)
        } catch let e as AppError {
            lastError = e
            showToast(e.localizedDescription, kind: .error)
        } catch {
            lastError = .unknown(error.localizedDescription)
            showToast(error.localizedDescription, kind: .error)
        }
    }
    
    func refreshQuote(symbol: String) async {
        guard let token = auth.accessToken else { return }
        do {
            let q = try await service.getQuote(symbol: symbol, token: token)
            quote = q
        } catch { }
    }
    
    func connectRealtimeIfPossible() {
        guard let token = auth.accessToken else { return }
        let url = URL(string: "wss://api.yourbroker.com/v1/quotes/stream")!
        let symbols = [selectedSymbol] + (portfolio?.holdings.prefix(15).map { $0.symbol } ?? [])
        quotesStream.connect(url: url, authToken: token, symbols: Array(Set(symbols.map { $0.uppercased() })))
    }
    
    func disconnectRealtime() {
        quotesStream.disconnect()
    }
    
    func searchSymbols(_ q: String) {
        guard let token = auth.accessToken else { return }
        let query = q.trimmingCharacters(in: .whitespacesAndNewlines)
        guard query.count >= 1 else {
            symbolResults = []
            return
        }
        debouncer.call(delay: 0.25) { [weak self] in
            guard let self else { return }
            do {
                let res = try await self.service.searchSymbols(query: query, token: token)
                await MainActor.run { self.symbolResults = Array(res.prefix(25)) }
            } catch {
                await MainActor.run { self.symbolResults = [] }
            }
        }
    }
    
    func selectSymbol(_ s: String) async {
        selectedSymbol = s.uppercased()
        symbolResults = []
        await refreshQuote(symbol: selectedSymbol)
        connectRealtimeIfPossible()
    }
    
    func validateOrderInput() -> Result<(Decimal, Decimal?), AppError> {
        let qtyStr = quantityText.trimmingCharacters(in: .whitespacesAndNewlines)
        guard let qty = Decimal(string: qtyStr), qty > 0 else {
            return .failure(.validation("Enter a valid quantity."))
        }
        var limit: Decimal? = nil
        if orderType == .limit {
            let lpStr = limitPriceText.trimmingCharacters(in: .whitespacesAndNewlines)
            guard let lp = Decimal(string: lpStr), lp > 0 else {
                return .failure(.validation("Enter a valid limit price."))
            }
            limit = lp.rounded(2)
        }
        return .success((qty, limit))
    }
    
    func estimatedCostOrProceeds(qty: Decimal, limit: Decimal?) -> Decimal? {
        let price: Decimal?
        if orderType == .limit { price = limit }
        else { price = quote?.last ?? quote?.ask }
        guard let p = price else { return nil }
        return (qty * p).rounded(2)
    }
    
    func placeOrder() async {
        guard let token = auth.accessToken else { return }
        let validation = validateOrderInput()
        switch validation {
        case .failure(let e):
            showToast(e.localizedDescription, kind: .error)
            return
        case .success(let (qty, limit)):
            isBusy = true
            defer { isBusy = false }
            do {
                let req = OrderRequest(
                    symbol: selectedSymbol.uppercased(),
                    assetType: .stock,
                    side: orderSide,
                    type: orderType,
                    quantity: qty,
                    limitPrice: limit,
                    timeInForce: tif,
                    clientOrderId: UUID.clientOrderId()
                )
                let placed = try await service.placeOrder(req, token: token)
                showToast("Order submitted: \(placed.symbol) \(placed.side.rawValue.uppercased()) \(fmtShares(placed.quantity))", kind: .success)
                await refreshAll()
            } catch let e as AppError {
                lastError = e
                showToast(e.localizedDescription, kind: .error)
            } catch {
                lastError = .unknown(error.localizedDescription)
                showToast(error.localizedDescription, kind: .error)
            }
        }
    }
    
    func cancelOrder(_ order: Order) async {
        guard let token = auth.accessToken else { return }
        isBusy = true
        defer { isBusy = false }
        do {
            let updated = try await service.cancelOrder(orderId: order.id, token: token)
            showToast("Canceled \(updated.symbol) order", kind: .info)
            await refreshAll()
        } catch let e as AppError {
            lastError = e
            showToast(e.localizedDescription, kind: .error)
        } catch {
            lastError = .unknown(error.localizedDescription)
            showToast(error.localizedDescription, kind: .error)
        }
    }
}

// MARK: - Toast

enum ToastKind { case info, success, error }

struct ToastMessage: Identifiable, Equatable {
    let id = UUID()
    let text: String
    let kind: ToastKind
}

struct ToastView: View {
    let message: ToastMessage
    var body: some View {
        Text(message.text)
            .font(.subheadline.weight(.semibold))
            .foregroundStyle(.white)
            .padding(.vertical, 10)
            .padding(.horizontal, 14)
            .background(background)
            .clipShape(RoundedRectangle(cornerRadius: 12, style: .continuous))
            .shadow(radius: 10)
            .padding(.horizontal, 16)
    }
    private var background: Color {
        switch message.kind {
        case .info: return .black.opacity(0.85)
        case .success: return .green.opacity(0.85)
        case .error: return .red.opacity(0.85)
        }
    }
}

