struct SegmentedPicker<T: Hashable & CaseIterable & RawRepresentable>: View where T.RawValue == String {
    let title: String
    @Binding var selection: T
    var body: some View {
        Picker(title, selection: $selection) {
            ForEach(Array(T.allCases), id: \.self) { item in
                Text(item.rawValue.capitalized).tag(item)
            }
        }
        .pickerStyle(.segmented)
    }
}

struct SymbolSearchBar: View {
    @Binding var text: String
    let onChange: (String) -> Void
    var body: some View {
        HStack(spacing: 10) {
            Image(systemName: "magnifyingglass")
                .foregroundStyle(.secondary)
            TextField("Search symbol (e.g., AAPL)", text: $text)
                .textInputAutocapitalization(.characters)
                .autocorrectionDisabled(true)
                .onChange(of: text) { _, newValue in onChange(newValue) }
            if !text.isEmpty {
                Button {
                    text = ""
                    onChange("")
                } label: {
                    Image(systemName: "xmark.circle.fill").foregroundStyle(.secondary)
                }
            }
        }
        .padding(.horizontal, 12)
        .padding(.vertical, 10)
        .background(Color(.secondarySystemBackground))
        .clipShape(RoundedRectangle(cornerRadius: 12, style: .continuous))
    }
}

struct OrderTicketView: View {
    @ObservedObject var state: TradingAppState
    @FocusState private var qtyFocused: Bool
    @FocusState private var limitFocused: Bool
    
    var body: some View {
        VStack(alignment: .leading, spacing: 14) {
            Text("Trade")
                .font(.headline)
            
            VStack(spacing: 12) {
                SegmentedPicker(title: "Side", selection: $state.orderSide)
                SegmentedPicker(title: "Type", selection: $state.orderType)
            }
            
            HStack(spacing: 12) {
                VStack(alignment: .leading, spacing: 6) {
                    Text("Quantity").font(.caption).foregroundStyle(.secondary)
                    TextField("0", text: $state.quantityText)
                        .keyboardType(.decimalPad)
                        .focused($qtyFocused)
                        .padding(12)
                        .background(Color(.secondarySystemBackground))
                        .clipShape(RoundedRectangle(cornerRadius: 12, style: .continuous))
                }
                
                if state.orderType == .limit {
                    VStack(alignment: .leading, spacing: 6) {
                        Text("Limit Price").font(.caption).foregroundStyle(.secondary)
                        TextField("0.00", text: $state.limitPriceText)
                            .keyboardType(.decimalPad)
                            .focused($limitFocused)
                            .padding(12)
                            .background(Color(.secondarySystemBackground))
                            .clipShape(RoundedRectangle(cornerRadius: 12, style: .continuous))
                    }
                }
            }
            
            HStack(spacing: 12) {
                Text("TIF").font(.caption).foregroundStyle(.secondary)
                Picker("TIF", selection: $state.tif) {
                    Text("DAY").tag("DAY")
                    Text("GTC").tag("GTC")
                }
                .pickerStyle(.segmented)
            }
            
            if let quote = state.quote, let qty = Decimal(string: state.quantityText.trimmingCharacters(in: .whitespacesAndNewlines)) {
                let limit = Decimal(string: state.limitPriceText.trimmingCharacters(in: .whitespacesAndNewlines))
                let estimate = state.estimatedCostOrProceeds(qty: qty, limit: limit)
                if let estimate {
                    HStack {
                        Text(state.orderSide == .buy ? "Est. Cost" : "Est. Proceeds")
                            .font(.caption)
                            .foregroundStyle(.secondary)
                        Spacer()
                        Text(fmtMoney(estimate))
                            .font(.subheadline.weight(.semibold))
                    }
                    .padding(12)
                    .background(Color(.secondarySystemBackground))
                    .clipShape(RoundedRectangle(cornerRadius: 12, style: .continuous))
                } else {
                    _ = quote
                }
            }
            
            Button {
                Task { await state.placeOrder() }
            } label: {
                HStack {
                    Spacer()
                    Text(state.isBusy ? "Submitting..." : "\(state.orderSide == .buy ? "Buy" : "Sell") \(state.selectedSymbol)")
                        .font(.headline)
                    Spacer()
                }
                .padding(.vertical, 14)
            }
            .buttonStyle(.borderedProminent)
            .tint(state.orderSide == .buy ? .blue : .orange)
            .disabled(state.isBusy)
        }
        .padding(14)
        .background(.thinMaterial)
        .clipShape(RoundedRectangle(cornerRadius: 16, style: .continuous))
        .onTapGesture { qtyFocused = false; limitFocused = false }
    }
}

