struct HoldingsList: View {
    let holdings: [Holding]
    let liveQuotes: [String: Quote]
    var body: some View {
        VStack(alignment: .leading, spacing: 10) {
            Text("Holdings").font(.headline)
            if holdings.isEmpty {
                Text("No positions yet.")
                    .font(.subheadline)
                    .foregroundStyle(.secondary)
                    .padding(.vertical, 8)
            } else {
                ForEach(holdings) { h in
                    let q = liveQuotes[h.symbol.uppercased()]
                    let mkt = q?.last ?? h.marketPrice
                    let mv = (h.quantity * mkt).rounded(2)
                    let pnl = (mv - (h.quantity * h.avgCost)).rounded(2)
                    HStack {
                        VStack(alignment: .leading, spacing: 2) {
                            Text(h.symbol).font(.subheadline.weight(.semibold))
                            Text("\(fmtShares(h.quantity)) shares")
                                .font(.caption)
                                .foregroundStyle(.secondary)
                        }
                        Spacer()
                        VStack(alignment: .trailing, spacing: 2) {
                            Text(fmtMoney(mv)).font(.subheadline.weight(.semibold))
                            Text((pnl >= 0 ? "+" : "") + fmtMoney(pnl))
                                .font(.caption.weight(.semibold))
                                .foregroundStyle(pnl >= 0 ? .green : .red)
                        }
                    }
                    .padding(10)
                    .background(Color(.secondarySystemBackground))
                    .clipShape(RoundedRectangle(cornerRadius: 12, style: .continuous))
                }
            }
        }
        .padding(14)
        .background(.thinMaterial)
        .clipShape(RoundedRectangle(cornerRadius: 16, style: .continuous))
    }
}

struct OrdersList: View {
    let orders: [Order]
    let onCancel: (Order) -> Void
    var body: some View {
        VStack(alignment: .leading, spacing: 10) {
            Text("Orders").font(.headline)
            if orders.isEmpty {
                Text("No recent orders.")
                    .font(.subheadline)
                    .foregroundStyle(.secondary)
                    .padding(.vertical, 8)
            } else {
                ForEach(orders.prefix(20)) { o in
                    VStack(alignment: .leading, spacing: 8) {
                        HStack {
                            Text("\(o.symbol) \(o.side.rawValue.uppercased())")
                                .font(.subheadline.weight(.semibold))
                            Spacer()
                            Text(o.status.rawValue)
                                .font(.caption.weight(.semibold))
                                .padding(.horizontal, 8)
                                .padding(.vertical, 4)
                                .background(statusColor(o.status).opacity(0.12))
                                .foregroundStyle(statusColor(o.status))
                                .clipShape(Capsule())
                        }
                        HStack {
                            Text("Qty \(fmtShares(o.quantity)) • Filled \(fmtShares(o.filledQuantity))")
                                .font(.caption)
                                .foregroundStyle(.secondary)
                            Spacer()
                            if let p = o.avgFillPrice {
                                Text("Avg \(fmtMoney(p))").font(.caption).foregroundStyle(.secondary)
                            } else if let lp = o.limitPrice {
                                Text("Limit \(fmtMoney(lp))").font(.caption).foregroundStyle(.secondary)
                            } else {
                                Text(o.type.rawValue.capitalized).font(.caption).foregroundStyle(.secondary)
                            }
                        }
                        HStack {
                            Text(o.createdAt.formatted(date: .abbreviated, time: .shortened))
                                .font(.caption2)
                                .foregroundStyle(.secondary)
                            Spacer()
                            if o.status == .pending || o.status == .partiallyFilled {
                                Button("Cancel") { onCancel(o) }
                                    .font(.caption.weight(.semibold))
                            }
                        }
                        if let reason = o.rejectionReason, !reason.isEmpty {
                            Text(reason)
                                .font(.caption)
                                .foregroundStyle(.red)
                        }
                    }
                    .padding(10)
                    .background(Color(.secondarySystemBackground))
                    .clipShape(RoundedRectangle(cornerRadius: 12, style: .continuous))
                }
            }
        }
        .padding(14)
        .background(.thinMaterial)
        .clipShape(RoundedRectangle(cornerRadius: 16, style: .continuous))
    }
    
    private func statusColor(_ s: OrderStatus) -> Color {
        switch s {
        case .pending: return .blue
        case .filled: return .green
        case .partiallyFilled: return .orange
        case .rejected: return .red
        case .canceled: return .gray
        }
    }
}

// MARK: - Screens

struct TradingHomeView: View {
    @StateObject var state = TradingAppState()
    @State private var searchText: String = ""
    
    var body: some View {
        NavigationStack {
            ScrollView {
                VStack(spacing: 14) {
                    SymbolSearchBar(text: $searchText, onChange: { q in state.searchSymbols(q) })
                    
                    if !state.symbolResults.isEmpty {
                        VStack(alignment: .leading, spacing: 8) {
                            ForEach(state.symbolResults, id: \.self) { s in
                                Button {
                                    Task {
                                        searchText = s
                                        await state.selectSymbol(s)
                                    }
                                } label: {
                                    HStack {
                                        Text(s).font(.subheadline.weight(.semibold))
                                        Spacer()
                                        Image(systemName: "arrow.up.right")
                                            .foregroundStyle(.secondary)
                                    }
                                    .padding(10)
                                    .background(Color(.secondarySystemBackground))
                                    .clipShape(RoundedRectangle(cornerRadius: 12, style: .continuous))
                                }
                                .buttonStyle(.plain)
                            }
                        }
                        .padding(14)
                        .background(.thinMaterial)
                        .clipShape(RoundedRectangle(cornerRadius: 16, style: .continuous))
                    }
                    
                    if let live = state.quotesStream.quotes[state.selectedSymbol.uppercased()] {
                        QuoteCard(quote: live)
                    } else if let quote = state.quote {
                        QuoteCard(quote: quote)
                    } else {
                        VStack(alignment: .leading, spacing: 8) {
                            Text(state.selectedSymbol).font(.title2.weight(.bold))
                            Text("Loading quote...")
                                .font(.subheadline)
                                .foregroundStyle(.secondary)
                        }
                        .frame(maxWidth: .infinity, alignment: .leading)
                        .padding(14)
                        .background(.thinMaterial)
                        .clipShape(RoundedRectangle(cornerRadius: 16, style: .continuous))
                    }
                    
                    OrderTicketView(state: state)
                    
                    if let p = state.portfolio {
                        PortfolioSummaryCard(portfolio: p)
                        HoldingsList(holdings: p.holdings, liveQuotes: state.quotesStream.quotes)
                    }
                    
                    OrdersList(orders: state.orders, onCancel: { o in
                        Task { await state.cancelOrder(o) }
                    })
                }
                .padding(14)
            }
            .navigationTitle("Trade")
            .toolbar {
                ToolbarItem(placement: .topBarTrailing) {
                    Button {
                        Task { await state.refreshAll() }
                    } label: {
                        Image(systemName: "arrow.clockwise")
                    }
                    .disabled(state.isBusy)
                }
            }
            .overlay(alignment: .top) {
                if let toast = state.toast {
                    ToastView(message: toast)
                        .transition(.move(edge: .top).combined(with: .opacity))
                        .padding(.top, 10)
                }
            }
            .onAppear {
                Task {
                    await state.refreshAll()
                    state.connectRealtimeIfPossible()
                }
            }
            .onDisappear {
                state.disconnectRealtime()
            }
        }
    }
}

// MARK: - Rapid Deployment: Demo Auth Screen (replace with your broker OAuth)

struct SignInRequest: Codable { let username: String; let password: String }
struct SignInResponse: Codable { let accessToken: String; let refreshToken: String?; let expiresInSeconds: Int; let accountId: String }

@MainActor
final class SignInViewModel: ObservableObject {
    @Published var username: String = ""
    @Published var password: String = ""
    @Published var isBusy: Bool = false
    @Published var errorText: String?
    
    private let api = APIClient.shared
    
    func signIn() async {
        let u = username.trimmingCharacters(in: .whitespacesAndNewlines)
        let p = password
        guard !u.isEmpty, !p.isEmpty else {
            errorText = "Enter username and password."
            return
        }
        isBusy = true
        defer { isBusy = false }
        errorText = nil
        do {
            let resp: SignInResponse = try await api.send(method: "POST", path: "/v1/auth/signin", body: SignInRequest(username: u, password: p), authToken: nil)
            let session = AuthSession(
                accessToken: resp.accessToken,
                refreshToken: resp.refreshToken,
                expiresAt: Date().addingTimeInterval(TimeInterval(resp.expiresInSeconds)),
                accountId: resp.accountId
            )
            AuthStore.shared.setSession(session)
        } catch let e as AppError {
            errorText = e.localizedDescription
        } catch {
            errorText = error.localizedDescription
        }
    }
}

