                                .autocorrectionDisabled(true)
                                .padding(12)
                                .background(Color(.secondarySystemBackground))
                                .clipShape(RoundedRectangle(cornerRadius: 12, style: .continuous))
                            
                            SecureField("Password", text: $vm.password)
                                .padding(12)
                                .background(Color(.secondarySystemBackground))
                                .clipShape(RoundedRectangle(cornerRadius: 12, style: .continuous))
                            
                            if let err = vm.errorText {
                                Text(err)
                                    .font(.caption)
