                                    .frame(maxWidth: .infinity, alignment: .leading)
                            }
                            
                            Button {
                                Task { await vm.signIn() }
                            } label: {
                                HStack {
                                    Spacer()
                                    Text(vm.isBusy ? "Signing in..." : "Sign In")
                                        .font(.headline)
                                    Spacer()
                                }
                                .padding(.vertical, 14)
                            }
                            .buttonStyle(.borderedProminent)
                            .disabled(vm.isBusy)
                            
                            Button("Use Demo Session (Local)") {
                                let demo = AuthSession(
