// MARK: - App

@main
struct TradingApp: App {
    init() {
        var cfg = APIConfig.default()
        cfg.baseURL = URL(string: "https://api.yourbroker.com")!
        cfg.apiKey = nil
        
        let secretService = "TradeApp.HMAC"
        let secretAccount = "secret"
        cfg.hmacSecretProvider = {
            (try? KeychainStore.shared.get(service: secretService, account: secretAccount)) ?? nil
        }
        
        _ = APIClient.shared
    }
    
    var body: some Scene {
        WindowGroup {
            RootView()
        }
    }
}